[
  {
    "text": "The LSOG mapping product and the Hagan et al. (2026) LiDAR classification product are compared at the identical 10 m spatial resolution and over the same geographic extent of Maine.",
    "topic": "Spatial resolution and extent match"
  },
  {
    "text": "The comparison uses a pixel-by-pixel agreement assessment between the two classified maps, with no reclassification or cross-walking of class labels.",
    "topic": "Direct pixel comparison without class harmonization"
  },
  {
    "text": "The comparison metrics (e.g., overall accuracy, class-level F1 scores) are computed identically for both the LSOG and LiDAR classifications against a common reference dataset.",
    "topic": "Common validation reference"
  },
  {
    "text": "Both the LSOG mapping and the LiDAR classification refer to the same publication year (2026) and same journal (Ecosphere) for the LiDAR data source.",
    "topic": "Source and date consistency"
  }
]
